class _DataScreenState extends State<DataScreen> {
  List<dynamic> _data = [];
  bool _isLoading = false;
  bool _isSyncing = false;
  String? _errorMessage;
  String? _syncMessage;

  @override
  void initState() {
    super.initState();
    _fetchData();
  }

  Future<void> _fetchData() async {
    setState(() {
      _isLoading = true;
      _errorMessage = null;
    });

    try {
      final data = await widget.apiClient.fetchData();
      setState(() {
        _data = data;
        _isLoading = false;
      });
    } catch (e) {
      setState(() {
        _errorMessage = e.toString();
        _isLoading = false;
      });
    }
  }

  Future<void> _syncData() async {
    setState(() {
      _isSyncing = true;
      _syncMessage = null;
    });

    try {
      final localData = _data.map((item) {
        if (item is Map<String, dynamic>) {
          return item;
        }
        return {'data': item};
      }).toList();

      final result = await widget.apiClient.syncData(localData);
      setState(() {
        _syncMessage = 'Sync successful: ${result['message'] ?? 'Complete'}';
        _isSyncing = false;
      });

      await _fetchData();
    } catch (e) {
      setState(() {
        _syncMessage = 'Sync failed: $e';
        _isSyncing = false;
      });
    }
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: const Text('Data'),
        actions: [
          IconButton(
            icon: _isSyncing
                ? const SizedBox(
                    width: 20,
                    height: 20,
                    child: CircularProgressIndicator(
                      strokeWidth: 2,
                      color: Colors.white,
                    ),
                  )
                : const Icon(Icons.sync),
            onPressed: _isSyncing ? null : _syncData,
          ),
        ],
      ),
      body: Column(
        children: [
          if (_syncMessage != null)
            Container(
              width: double.infinity,
              padding: const EdgeInsets.all(8),
              color: _syncMessage!.contains('successful')
                  ? Colors.green.shade100
                  : Colors.orange.shade100,
              child: Text(
                _syncMessage!,
                textAlign: TextAlign.center,
              ),
            ),
          Expanded(
            child: _isLoading
                ? const Center(child: CircularProgressIndicator())
                : _errorMessage != null
                    ? Center(
                        child: Column(
                          mainAxisAlignment: MainAxisAlignment.center,
                          children: [
                            Text(
                              _errorMessage!,
                              style: const TextStyle(color: Colors.red),
                            ),
                            const SizedBox(height: 16),
                            ElevatedButton(
                              onPressed: _fetchData,
                              child: const Text('Retry'),
                            ),
                          ],
                        ),
                      )
                    : _data.isEmpty
                        ? const Center(child: Text('No data available'))
                        : RefreshIndicator(
                            onRefresh: _fetchData,
                            child: ListView.builder(
                              padding: const EdgeInsets.all(16),
                              itemCount: _data.length,
                              itemBuilder: (context, index) {
                                final item = _data[index];
                                return Card(
                                  margin: const EdgeInsets.only(bottom: 8),
                                  child: ListTile(
                                    title: Text(
                                      item is Map
                                          ? item['title']?.toString() ?? 'Item ${index + 1}'
                                          : item.toString(),
                                    ),
                                    subtitle: item is Map && item['description'] != null
                                        ? Text(item['description'].toString())
                                        : null,
                                  ),
                                );
                              },
                            ),
                          ),
          ),
        ],
      ),
    );
  }
